// Compute the canonical week_start (Monday of current ISO week, Kyiv local)
// + iterate over 4 personas. n8n schedule-trigger fires on Monday 09:00
// already; we still derive the date defensively (and so the same workflow
// can be re-fired manually any weekday for backfill).
//
// PR-34 skeleton: один founder_user_id, переданий через env STRATEGIC_FOUNDER_USER_ID.
// PR-35+: розширюємо на multiple founders через DB-query.

const PERSONAS = ['finyk', 'fizruk', 'nutrition', 'routine'];
const founderUserId = $env.STRATEGIC_FOUNDER_USER_ID || '';

// Kyiv-local Monday: find the most recent Monday-or-today у Kyiv TZ.
const nowKyiv = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Kyiv' }));
const dow = nowKyiv.getDay(); // 0=Sun, 1=Mon, ..., 6=Sat
const daysSinceMonday = (dow + 6) % 7; // Mon=0, Tue=1, ..., Sun=6
const monday = new Date(nowKyiv);
monday.setDate(monday.getDate() - daysSinceMonday);
const weekStart = monday.toISOString().slice(0, 10);

return PERSONAS.map((persona) => ({ json: { persona, founderUserId, weekStart } }));
